'use client';

import { useState } from 'react';
import Link from 'next/link';
import {
  Mail,
  Phone,
  MapPin,
  Clock,
  Instagram,
  Facebook,
  Youtube,
  CheckCircle2,
} from 'lucide-react';
import ScrollReveal from '@/components/ScrollReveal';
import { SITE_CONFIG } from '@/lib/constants';

export default function ContactPage() {
  const [form, setForm] = useState({
    name: '',
    email: '',
    phone: '',
    subject: '',
    message: '',
  });
  const [submitted, setSubmitted] = useState(false);
  const [newsletterEmail, setNewsletterEmail] = useState('');
  const [newsletterSubmitted, setNewsletterSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
  };

  const handleNewsletterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setNewsletterSubmitted(true);
  };

  const contactInfo = [
    {
      icon: Mail,
      label: 'Email',
      value: SITE_CONFIG.email,
      href: `mailto:${SITE_CONFIG.email}`,
      description: 'We reply within 24 hours',
    },
    {
      icon: Phone,
      label: 'Phone',
      value: SITE_CONFIG.phone,
      href: `tel:${SITE_CONFIG.phone}`,
      description: 'Mon - Fri, 9am - 6pm EST',
    },
    {
      icon: MapPin,
      label: 'Studio',
      value: SITE_CONFIG.address,
      href: 'https://maps.google.com',
      description: 'By appointment only',
    },
    {
      icon: Clock,
      label: 'Business Hours',
      value: 'Mon - Fri: 9AM - 6PM',
      href: '#',
      description: 'Weekend sessions available',
    },
  ];

  const socials = [
    { icon: Instagram, label: 'Instagram', href: SITE_CONFIG.instagram },
    { icon: Facebook, label: 'Facebook', href: SITE_CONFIG.facebook },
    { icon: Youtube, label: 'YouTube', href: SITE_CONFIG.youtube },
  ];

  const subjectOptions = [
    'Wedding Inquiry',
    'Engagement Session',
    'Portrait Session',
    'Commercial Project',
    'Print Order Question',
    'General Question',
  ];

  return (
    <>
      {/* ── Hero ── */}
      <section className="bg-bg pt-40 pb-16 px-6">
        <div className="max-w-[980px] mx-auto text-center">
          <p className="text-gold text-[11px] tracking-[0.2em] uppercase font-medium mb-5">
            Contact
          </p>
          <h1 className="font-serif text-5xl md:text-7xl text-text-primary leading-[1.08] mb-5">
            Let&apos;s Start Your Story
          </h1>
          <p className="text-text-secondary text-base md:text-lg leading-relaxed max-w-xl mx-auto">
            Whether you&apos;re ready to book or just exploring, we&apos;d love to hear
            from you. Every great image begins with a conversation.
          </p>
        </div>
      </section>

      {/* ── Contact Form + Info ── */}
      <section className="bg-bg-white py-24 px-6">
        <div className="max-w-[1200px] mx-auto">
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-14">
            {/* Left Column: Form */}
            <div className="lg:col-span-3">
              <ScrollReveal>
                {submitted ? (
                  <div className="bg-white rounded-2xl border border-border p-10 md:p-14 text-center flex flex-col items-center justify-center min-h-[560px]">
                    <div className="w-16 h-16 rounded-full bg-gold-bg flex items-center justify-center mb-6">
                      <CheckCircle2 size={32} className="text-gold" />
                    </div>
                    <h3 className="font-serif text-3xl text-text-primary mb-3">
                      Message Sent
                    </h3>
                    <p className="text-text-secondary text-sm max-w-sm mb-8 leading-relaxed">
                      Thank you for reaching out
                      {form.name ? `, ${form.name.split(' ')[0]}` : ''}! We&apos;ll
                      get back to you within 24 hours.
                    </p>
                    <div className="flex flex-col sm:flex-row gap-3">
                      <Link href="/portfolio" className="btn-primary px-6 py-3 text-sm">
                        View Portfolio
                      </Link>
                      <button
                        onClick={() => {
                          setSubmitted(false);
                          setForm({ name: '', email: '', phone: '', subject: '', message: '' });
                        }}
                        className="btn-secondary px-6 py-3 text-sm"
                      >
                        Send Another
                      </button>
                    </div>
                  </div>
                ) : (
                  <div>
                    <p className="text-gold text-[11px] tracking-[0.2em] uppercase font-medium mb-6">
                      Send a Message
                    </p>

                    <form onSubmit={handleSubmit} className="space-y-5">
                      {/* Name + Email */}
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                        <div>
                          <label className="text-text-tertiary text-xs tracking-wider uppercase mb-2 block">
                            Full Name <span className="text-gold">*</span>
                          </label>
                          <input
                            type="text"
                            required
                            value={form.name}
                            onChange={(e) => setForm({ ...form, name: e.target.value })}
                            className="input-apple"
                            placeholder="John Doe"
                          />
                        </div>
                        <div>
                          <label className="text-text-tertiary text-xs tracking-wider uppercase mb-2 block">
                            Email Address <span className="text-gold">*</span>
                          </label>
                          <input
                            type="email"
                            required
                            value={form.email}
                            onChange={(e) => setForm({ ...form, email: e.target.value })}
                            className="input-apple"
                            placeholder="hello@example.com"
                          />
                        </div>
                      </div>

                      {/* Phone */}
                      <div>
                        <label className="text-text-tertiary text-xs tracking-wider uppercase mb-2 block">
                          Phone Number
                        </label>
                        <input
                          type="tel"
                          value={form.phone}
                          onChange={(e) => setForm({ ...form, phone: e.target.value })}
                          className="input-apple"
                          placeholder="+1 (555) 123-4567"
                        />
                      </div>

                      {/* Subject */}
                      <div>
                        <label className="text-text-tertiary text-xs tracking-wider uppercase mb-2 block">
                          Subject <span className="text-gold">*</span>
                        </label>
                        <select
                          required
                          value={form.subject}
                          onChange={(e) => setForm({ ...form, subject: e.target.value })}
                          className={`input-apple appearance-none cursor-pointer ${
                            !form.subject ? 'text-text-tertiary' : ''
                          }`}
                        >
                          <option value="">Select a subject</option>
                          {subjectOptions.map((opt) => (
                            <option key={opt} value={opt}>
                              {opt}
                            </option>
                          ))}
                        </select>
                      </div>

                      {/* Message */}
                      <div>
                        <label className="text-text-tertiary text-xs tracking-wider uppercase mb-2 block">
                          Your Message <span className="text-gold">*</span>
                        </label>
                        <textarea
                          required
                          rows={5}
                          value={form.message}
                          onChange={(e) => setForm({ ...form, message: e.target.value })}
                          className="input-apple resize-none"
                          placeholder="Tell us about your vision, preferred dates, and any details you'd like to share..."
                        />
                      </div>

                      {/* Submit */}
                      <button
                        type="submit"
                        className="btn-primary w-full py-4 text-sm"
                      >
                        Send Message
                      </button>

                      <p className="text-text-tertiary text-xs text-center">
                        We respond within 24 hours. Your information is never shared.
                      </p>
                    </form>
                  </div>
                )}
              </ScrollReveal>
            </div>

            {/* Right Column: Contact Info */}
            <div className="lg:col-span-2 space-y-5">
              {contactInfo.map((item, i) => (
                <ScrollReveal key={item.label} delay={i * 0.08}>
                  <a
                    href={item.href}
                    target={item.href.startsWith('http') ? '_blank' : undefined}
                    rel={item.href.startsWith('http') ? 'noopener noreferrer' : undefined}
                    className="card p-6 block group"
                  >
                    <item.icon size={20} className="text-gold mb-3" />
                    <p className="text-text-tertiary text-xs tracking-[0.15em] uppercase mb-1">
                      {item.label}
                    </p>
                    <p className="text-text-primary text-sm font-medium group-hover:text-gold transition-colors">
                      {item.value}
                    </p>
                    <p className="text-text-tertiary text-xs mt-1">
                      {item.description}
                    </p>
                  </a>
                </ScrollReveal>
              ))}

              {/* Social Media */}
              <ScrollReveal delay={0.35}>
                <div className="card p-6">
                  <p className="text-text-tertiary text-xs tracking-[0.15em] uppercase mb-4">
                    Follow Along
                  </p>
                  <div className="flex gap-3">
                    {socials.map((social) => (
                      <a
                        key={social.label}
                        href={social.href}
                        target="_blank"
                        rel="noopener noreferrer"
                        aria-label={social.label}
                        className="w-11 h-11 rounded-full bg-bg-light flex items-center justify-center text-text-secondary hover:bg-gold hover:text-white transition-all duration-300"
                      >
                        <social.icon size={18} />
                      </a>
                    ))}
                  </div>
                </div>
              </ScrollReveal>
            </div>
          </div>
        </div>
      </section>

      {/* ── Newsletter ── */}
      <section className="bg-bg-light py-24 px-6 text-center">
        <ScrollReveal>
          <div className="max-w-xl mx-auto">
            <h2 className="font-serif text-3xl md:text-5xl text-text-primary leading-[1.1] mb-4">
              Stay Inspired
            </h2>
            <p className="text-text-secondary text-base leading-relaxed mb-8 max-w-md mx-auto">
              Get exclusive behind-the-scenes content, photography tips, and early
              access to new print collections.
            </p>

            {newsletterSubmitted ? (
              <div className="flex flex-col items-center gap-3">
                <div className="w-12 h-12 rounded-full bg-gold-bg flex items-center justify-center">
                  <CheckCircle2 size={22} className="text-gold" />
                </div>
                <p className="text-text-primary text-sm font-medium">
                  You&apos;re on the list!
                </p>
                <p className="text-text-tertiary text-xs">
                  Check your inbox to confirm your subscription.
                </p>
              </div>
            ) : (
              <form
                onSubmit={handleNewsletterSubmit}
                className="flex flex-col sm:flex-row gap-3 max-w-md mx-auto"
              >
                <input
                  type="email"
                  required
                  value={newsletterEmail}
                  onChange={(e) => setNewsletterEmail(e.target.value)}
                  className="input-apple flex-1"
                  placeholder="Enter your email"
                />
                <button type="submit" className="btn-primary px-6 py-4 text-sm whitespace-nowrap">
                  Subscribe
                </button>
              </form>
            )}

            {!newsletterSubmitted && (
              <p className="text-text-tertiary text-xs mt-4">
                No spam, ever. Unsubscribe anytime.
              </p>
            )}
          </div>
        </ScrollReveal>
      </section>

      {/* ── Map ── */}
      <section className="bg-bg-white px-6 py-24">
        <div className="max-w-[1200px] mx-auto">
          <ScrollReveal>
            <div className="rounded-xl overflow-hidden h-80 md:h-96">
              <iframe
                src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d100939.98555600847!2d-77.49428799999999!3d37.5407246!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x89b111095799c9ed%3A0xbfd83a85c5e6c0b5!2sRichmond%2C%20VA!5e0!3m2!1sen!2sus!4v1700000000000!5m2!1sen!2sus"
                width="100%"
                height="100%"
                style={{
                  border: 0,
                  filter: 'grayscale(0.3) brightness(1.05)',
                }}
                allowFullScreen
                loading="lazy"
                referrerPolicy="no-referrer-when-downgrade"
                title="Studio Location"
              />
            </div>
          </ScrollReveal>
        </div>
      </section>
    </>
  );
}
